import os
import threading
import zmq
from typing import Dict, Any, Tuple


def start_zmq_server(bind_address: str = "tcp://127.0.0.1:5555") -> Tuple[threading.Thread, Dict[str, Any], threading.Condition]:
    """
    Starts a ZeroMQ REP server in a background thread.

    Returns:
        (thread, shared_data, condition) – the thread running the server,
        a dictionary used as shared data store, and a Condition object for
        synchronising access to that dictionary.
    """
    # Register the address in the environment
    os.environ["ZMQ_SERVER_ADDRESS"] = bind_address

    # Shared data and synchronisation primitive
    shared_data: Dict[str, Any] = {}
    data_cond = threading.Condition()

    # ZeroMQ context and socket
    context = zmq.Context()
    socket = context.socket(zmq.REP)
    socket.bind(bind_address)

    def server_loop() -> None:
        while True:
            try:
                # Wait for next request from client
                msg = socket.recv_json()
                # Expected message format: {"cmd": "set"/"get", "key": ..., "value": ...}
                cmd = msg.get("cmd")
                key = msg.get("key")

                with data_cond:
                    if cmd == "set":
                        shared_data[key] = msg.get("value")
                        response = {"status": "ok"}
                    elif cmd == "get":
                        response = {"status": "ok", "value": shared_data.get(key)}
                    elif cmd == "delete":
                        shared_data.pop(key, None)
                        response = {"status": "ok"}
                    else:
                        response = {"status": "error", "error": "unknown command"}

                # Send reply back to client
                socket.send_json(response)
            except zmq.ZMQError as e:
                # Socket closed or other ZMQ error – exit loop
                break
            except Exception as e:
                # Unexpected error – reply with error info
                socket.send_json({"status": "error", "error": str(e)})

    server_thread = threading.Thread(target=server_loop, daemon=True, name="ZMQServerThread")
    server_thread.start()

    return server_thread, shared_data, data_cond
