import json
from typing import Callable, Dict, Any


class JsonObject:
    """Base class for objects that can be serialized to/from JSON."""

    # Registry of factory functions keyed by an identifier
    _registry: Dict[str, Callable[..., "JsonObject"]] = {}

    def __init__(self, **kwargs: Any):
        """Initialize the object with arbitrary attributes."""
        for key, value in kwargs.items():
            setattr(self, key, value)

    # --------------------------------------------------------------------- #
    # Serialization / Deserialization
    # --------------------------------------------------------------------- #
    def to_json(self, *, indent: int = None) -> str:
        """Return a JSON string representation of the object's __dict__."""
        return json.dumps(self.__dict__, indent=indent)

    @classmethod
    def from_json(cls, json_str: str) -> "JsonObject":
        """Create an instance of *cls* from a JSON string."""
        data = json.loads(json_str)
        return cls(**data)

    # --------------------------------------------------------------------- #
    # Registry handling (class methods)
    # --------------------------------------------------------------------- #
    @classmethod
    def register_factory(cls, id_: str, factory: Callable[..., "JsonObject"]) -> None:
        """Add a factory function to the registry under *id_*."""
        if not callable(factory):
            raise TypeError("factory must be callable")
        cls._registry[id_] = factory

    @classmethod
    def get_factory(cls, id_: str) -> Callable[..., "JsonObject"]:
        """Retrieve a factory function by *id_*; raises KeyError if missing."""
        try:
            return cls._registry[id_]
        except KeyError as exc:
            raise KeyError(f"No factory registered for id '{id_}'") from exc

    @classmethod
    def create_from_id(cls, id_: str, *args: Any, **kwargs: Any) -> "JsonObject":
        """Create a new instance using the factory associated with *id_*."""
        factory = cls.get_factory(id_)
        return factory(*args, **kwargs)


# ------------------------------------------------------------------------- #
# Helper functions that operate on the JsonObject registry
# ------------------------------------------------------------------------- #
def add_factory(id_: str, factory: Callable[..., JsonObject]) -> None:
    """Convenient wrapper to add a factory to the JsonObject registry."""
    JsonObject.register_factory(id_, factory)


def create_instance(id_: str, *args: Any, **kwargs: Any) -> JsonObject:
    """Convenient wrapper to create an instance via the JsonObject registry."""
    return JsonObject.create_from_id(id_, *args, **kwargs)


# ------------------------------------------------------------------------- #
# Example subclass and registration
