from dataclasses import dataclass

@dataclass
class ParsedResult:
    type: int
    intensity: int
    size: int
    generation: int
    choice: int

def parse_string(s: str) -> ParsedResult:
    """
    Parse a string containing the keys: type, intensity, size, generation, choice.
    Expected format (order not important):
        "type=1, intensity=2, size=3, generation=4, choice=5"
    Delimiters can be commas, semicolons or whitespace.
    Values are evaluated with eval() to allow integer literals like 0x10, 1<<3, etc.
    Raises ValueError for malformed input.
    """
    if not isinstance(s, str):
        raise ValueError("Input must be a string")

    # Normalise delimiters to commas
    for delim in (';', '\n'):
        s = s.replace(delim, ',')
    parts = [p.strip() for p in s.split(',') if p.strip()]

    required_keys = {"type", "intensity", "size", "generation", "choice"}
    parsed = {}

    for part in parts:
        # Accept both "=" and ":" as separators
        if '=' in part:
            key, val = part.split('=', 1)
        elif ':' in part:
            key, val = part.split(':', 1)
        else:
            raise ValueError(f"Invalid segment '{part}': missing separator")
        key = key.strip().lower()
        val = val.strip()
        if key not in required_keys:
            raise ValueError(f"Unexpected key '{key}'")
        try:
            # Use eval to convert the string to an integer (e.g., "0x10", "1<<3")
            int_val = eval(val, {"__builtins__": {}}, {})
            if not isinstance(int_val, int):
                raise ValueError
        except Exception as e:
            raise ValueError(f"Invalid integer value for '{key}': {val}") from e
        parsed[key] = int_val

    missing = required_keys - parsed.keys()
    if missing:
        raise ValueError(f"Missing required keys: {', '.join(sorted(missing))}")

    return ParsedResult(
        type=parsed["type"],
        intensity=parsed["intensity"],
        size=parsed["size"],
        generation=parsed["generation"],
        choice=parsed["choice"]
    )
