class TypeMeta(type):
    """
    Metaclass that injects a custom ``__new__`` into the created class.
    If the class is instantiated without positional arguments, a random
    string is generated and passed as the first argument.
    """

    def __new__(mcls, name: str, bases: tuple[type, ...], namespace: dict[str, Any], **kw):
        # Preserve any existing __new__ defined in the class body
        original_new = namespace.get('__new__')

        def __new__(cls, *args, **kwargs):
            # If no positional arguments were supplied, create a random one
            if not args:
                # Example: 12‑character alphanumeric string
                rand_arg = random_string(12, string.ascii_letters + string.digits)
                args = (rand_arg,)

            # If the class defined its own __new__, delegate to it
            if original_new:
                return original_new(cls, *args, **kwargs)

            # Default behaviour – allocate the instance normally
            return super(cls, cls).__new__(cls)

        # Replace/insert the generated __new__ into the class dict
        namespace['__new__'] = __new__

        # Create the new class using the standard ``type`` machinery
        return super().__new__(mcls, name, bases, namespace, **kw)


# Example usage --------------------------------------------------------------

class Example(metaclass=TypeMeta):
    def __init__(self, value):
        self.value = value

    def __repr__(self) -> str:
        return f"{self.__class__.__name__}(value={self.value!r})"


# Demonstration
if __name__ == "__main__":
    # Explicit argument – uses the provided value
    e1 = Example("explicit")
    print(e1)  # Example(value='explicit')

    # No argument – a random string is generated automatically
    e2 = Example()
    print(e2)  # Example(value='a1B2c3D4e5F6')
