CREATE OR REPLACE FUNCTION demo_cursor()
RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    cur CURSOR FOR
        SELECT *
        FROM (VALUES
                (1, 'Alice'),
                (2, 'Bob'),
                (3, 'Charlie')
             ) AS src(id, name);
    rec RECORD;
BEGIN
    -- Create the table
    CREATE TEMP TABLE my_table (
        id   INTEGER,
        name TEXT
    );

    -- Open cursor and insert rows
    OPEN cur;
    LOOP
        FETCH cur INTO rec;
        EXIT WHEN NOT FOUND;
        INSERT INTO my_table (id, name) VALUES (rec.id, rec.name);
    END LOOP;
    CLOSE cur;

    -- Drop the table
    DROP TABLE my_table;
END;
$$;
