import json
from typing import Any, Dict


class Quantity:
    """
    Represents a numeric quantity with an amount, a unit and optional error bounds.
    """

    def __init__(self, data: Dict[str, Any]) -> None:
        """
        Initialise from a plain JSON‑like dictionary.

        Expected keys:
            - amount: the numeric value (as string or number)
            - unit:   the unit identifier (string)
            - upperBound: the upper error bound (optional, string or number)
        """
        if not isinstance(data, dict):
            raise TypeError("Quantity expects a dict as input")

        try:
            self.amount = data["amount"]
            self.unit = data["unit"]
            self.upperBound = data.get("upperBound")
        except KeyError as exc:
            raise ValueError(f"Missing required field {exc.args[0]} in Quantity data") from exc

    @classmethod
    def fromWikibase(cls, wb_json: Dict[str, Any]) -> "Quantity":
        """
        Build a Quantity from a Wikibase JSON object.

        Wikibase quantity values are typically nested like:
            {
                "mainsnak": {
                    "datavalue": {
                        "value": {
                            "amount": "+123",
                            "unit": "http://www.wikidata.org/entity/Q11573",
                            "upperBound": "+124",
                            "lowerBound": "+122"
                        },
                        "type": "quantity"
                    }
                }
            }

        The method extracts the inner ``value`` dict (or uses the supplied dict
        directly if it already contains the expected keys) and forwards it to the
        regular constructor.
        """
        # Try to locate the innermost value dict
        value = wb_json
        for key in ("mainsnak", "datavalue", "value"):
            if isinstance(value, dict) and key in value:
                value = value[key]
            else:
                break

        if not isinstance(value, dict):
            raise ValueError("Unable to locate a quantity value in the provided Wikibase JSON")

        # The Wikibase amount strings often start with a leading '+'; strip it for consistency
        amount = value.get("amount")
        if isinstance(amount, str):
            amount = amount.lstrip("+")

        upper = value.get("upperBound")
        if isinstance(upper, str):
            upper = upper.lstrip("+")

        # Build a simple dict compatible with the regular constructor
        data = {
            "amount": amount,
            "unit": value.get("unit"),
            "upperBound": upper,
        }

        return cls(data)

    def __str__(self) -> str:
        """Return a JSON string representation of the quantity."""
        return json.dumps(
            {
                "amount": self.amount,
                "unit": self.unit,
                "upperBound": self.upperBound,
            },
            ensure_ascii=False,
            sort_keys=True,
        )

    def __eq__(self, other: Any) -> bool:
        """Two Quantity objects are equal if their fields match exactly."""
        if not isinstance(other, Quantity):
            return NotImplemented
        return (
            self.amount == other.amount
            and self.unit == other.unit
            and self.upperBound == other.upperBound
        )
