import argparse
import hashlib
import os
import sys


def compute_hash(path: str) -> str:
    """Return SHA256 hash of the file's contents."""
    h = hashlib.sha256()
    with open(path, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            h.update(chunk)
    return h.hexdigest()


def load_stored_hash(version_file: str) -> str | None:
    """Read the stored hash from version_file, if it exists."""
    if not os.path.isfile(version_file):
        return None
    with open(version_file, "r", encoding="utf-8") as f:
        return f.read().strip() or None


def save_hash(version_file: str, hash_val: str) -> None:
    """Write the hash to version_file."""
    with open(version_file, "w", encoding="utf-8") as f:
        f.write(hash_val + "\n")


def main() -> None:
    parser = argparse.ArgumentParser(
        description="Check a file's contents against a stored version and update if needed."
    )
    parser.add_argument("target", help="Path to the file whose contents are to be checked.")
    parser.add_argument(
        "-v",
        "--version-file",
        default=".file_version",
        help="Path to the file storing the previous hash (default: .file_version).",
    )
    args = parser.parse_args()

    if not os.path.isfile(args.target):
        sys.stderr.write(f"Error: target file '{args.target}' does not exist.\n")
        sys.exit(1)

    current_hash = compute_hash(args.target)
    stored_hash = load_stored_hash(args.version_file)

    if stored_hash == current_hash:
        print("No changes detected.")
    else:
        if stored_hash is None:
            print("No stored version found. Storing current version.")
        else:
            print("Change detected. Updating stored version.")
        save_hash(args.version_file, current_hash)
        print(f"Updated version hash: {current_hash}")


if __name__ == "__main__":
    main()
