import gym
import tensorflow as tf
from stable_baselines3.common.vec_env import SubprocVecEnv, DummyVecEnv


class CustomRewardWrapper(gym.Wrapper):
    """Wrap an env to modify its reward using a parameter dict."""

    def __init__(self, env, params):
        super().__init__(env)
        self.params = params or {}

    def step(self, action):
        obs, reward, done, info = self.env.step(action)
        reward = self._modify_reward(reward, obs, done, info)
        return obs, reward, done, info

    def _modify_reward(self, reward, obs, done, info):
        # Example modification: scale + optional penalty
        scale = self.params.get("scale", 1.0)
        penalty = self.params.get("penalty", 0.0)
        # If a custom callable is supplied, use it
        func = self.params.get("func")
        if callable(func):
            return func(reward, obs, done, info, **self.params)
        return reward * scale - penalty


def configure_env(env_id, num_envs=1, reward_params=None, seed=None, use_subproc=False):
    """
    Configure a deep RL environment:
    - Enable GPU memory growth (TensorFlow).
    - Create a vectorized environment (DummyVecEnv or SubprocVecEnv).
    - Optionally wrap the env with a custom reward function.

    Returns:
        VecEnv: a vectorized environment ready for training.
    """
    # Enable GPU memory growth for all visible GPUs
    gpus = tf.config.experimental.list_physical_devices("GPU")
    for gpu in gpus:
        try:
            tf.config.experimental.set_memory_growth(gpu, True)
        except Exception:
            pass  # ignore GPUs that cannot be configured

    # Helper to create a single env instance
    def make_env(rank):
        def _init():
            env = gym.make(env_id)
            if seed is not None:
                env.seed(seed + rank)
                env.action_space.seed(seed + rank)
                env.observation_space.seed(seed + rank)
            if reward_params:
                env = CustomRewardWrapper(env, reward_params)
            return env
        return _init

    env_fns = [make_env(i) for i in range(num_envs)]

    if use_subproc and num_envs > 1:
        vec_env = SubprocVecEnv(env_fns)
    else:
        vec_env = DummyVecEnv(env_fns)

    return vec_env
