import sqlite3
import sys

def prompt(message: str) -> str:
    return input(message).strip()

def get_db_connection(db_name: str) -> sqlite3.Connection:
    try:
        conn = sqlite3.connect(db_name)
        return conn
    except sqlite3.Error as e:
        print(f"Error connecting to database: {e}")
        sys.exit(1)

def create_table(conn: sqlite3.Connection, table_name: str, schema: str) -> None:
    try:
        conn.execute(f"CREATE TABLE IF NOT EXISTS {table_name} ({schema});")
        conn.commit()
        print(f"Table '{table_name}' created (or already exists).")
    except sqlite3.Error as e:
        print(f"Error creating table: {e}")
        sys.exit(1)

def insert_record(conn: sqlite3.Connection, table_name: str, columns: list, values: list) -> None:
    placeholders = ", ".join("?" for _ in values)
    cols = ", ".join(columns)
    sql = f"INSERT INTO {table_name} ({cols}) VALUES ({placeholders});"
    try:
        conn.execute(sql, values)
        conn.commit()
        print("Record inserted.")
    except sqlite3.Error as e:
        print(f"Error inserting record: {e}")

def main() -> None:
    db_name = prompt("Enter SQLite database filename (e.g., mydb.sqlite): ")
    conn = get_db_connection(db_name)

    table_name = prompt("Enter table name: ")
    schema = prompt(
        "Enter table schema (e.g., id INTEGER PRIMARY KEY, name TEXT, age INTEGER): "
    )
    create_table(conn, table_name, schema)

    # Extract column names from schema for later inserts
    columns = [col.split()[0] for col in schema.split(",")]

    while True:
        raw_vals = prompt(
            f"Enter values for columns {columns} separated by commas (or type 'quit' to exit): "
        )
        if raw_vals.lower() in {"quit", "exit"}:
            break
        # Simple parsing: split on commas and strip whitespace
        values = [v.strip() for v in raw_vals.split(",")]
        # Convert numeric strings to int or float where appropriate
        converted = []
        for v in values:
            if v.isdigit():
                converted.append(int(v))
            else:
                try:
                    converted.append(float(v))
                except ValueError:
                    converted.append(v)  # keep as string
        if len(converted) != len(columns):
            print(f"Expected {len(columns)} values, got {len(converted)}. Try again.")
            continue
        insert_record(conn, table_name, columns, converted)

    conn.close()
    print("Database connection closed.")

if __name__ == "__main__":
    main()
