import subprocess
import shlex

def _run_cmd(cmd):
    """Run a shell command and return (stdout, stderr, returncode)."""
    proc = subprocess.Popen(
        shlex.split(cmd), stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True
    )
    out, err = proc.communicate()
    return out.strip(), err.strip(), proc.returncode

def _get_volume_pactl():
    out, err, rc = _run_cmd("pactl get-sink-volume @DEFAULT_SINK@")
    if rc != 0:
        raise RuntimeError(f"pactl error: {err}")
    # Example output: "Volume: front-left: 65536 / 100% ... "
    for part in out.split():
        if part.endswith('%'):
            return part.strip('%')
    raise RuntimeError("Unable to parse volume from pactl output")

def _get_volume_amixer():
    out, err, rc = _run_cmd("amixer get Master")
    if rc != 0:
        raise RuntimeError(f"amixer error: {err}")
    # Look for something like "[75%]"
    for token in out.split():
        if token.startswith('[') and token.endswith(']%]'):
            return token.strip('[]%')
        if token.startswith('[') and token.endswith('%]'):
            return token.strip('[]%')
    raise RuntimeError("Unable to parse volume from amixer output")

def _get_current_volume():
    try:
        return _get_volume_pactl()
    except Exception:
        return _get_volume_amixer()

def _change_volume(direction):
    step = "5%"  # change step size
    if direction == "up":
        cmd = f"pactl set-sink-volume @DEFAULT_SINK@ +{step}"
    elif direction == "down":
        cmd = f"pactl set-sink-volume @DEFAULT_SINK@ -{step}"
    else:
        raise ValueError("Unsupported direction")
    out, err, rc = _run_cmd(cmd)
    if rc != 0:
        # fallback to amixer
        if direction == "up":
            cmd = f"amixer set Master {step}+"
        else:
            cmd = f"amixer set Master {step}-"
        out, err, rc = _run_cmd(cmd)
        if rc != 0:
            raise RuntimeError(f"Failed to adjust volume: {err}")

def adjust_volume(command: str) -> str:
