    match = re.search(pattern, output, re.MULTILINE)
    if not match:
        raise ValueError("Pattern not found in output")
    value = match.group(1)
    if expected_regex and not re.fullmatch(expected_regex, value):
        raise ValueError(f"Extracted value '{value}' does not match expected format")
    return value

