import functools
import types
from typing import Any, Callable, Dict


def create_updated_function(
    func: Callable[..., Any], updates: Dict[str, Any]
) -> Callable[..., Any]:
    """
    Return a new function that behaves like *func* but with its global namespace
    temporarily patched with the key/value pairs from *updates*.

    The new function keeps the original name, docstring, annotations and
    returns the same type of value as the original function.
    """

    if not callable(func):
        raise TypeError("func must be callable")
    if not isinstance(updates, dict):
        raise TypeError("updates must be a dictionary")

    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        # Save original globals that will be overwritten
        orig_globals = func.__globals__
        backup = {}
        for name, value in updates.items():
            if name in orig_globals:
                backup[name] = orig_globals[name]
            orig_globals[name] = value
        try:
            return func(*args, **kwargs)
        finally:
            # Restore original globals
            for name in updates:
                if name in backup:
                    orig_globals[name] = backup[name]
                else:
                    del orig_globals[name]

    # Preserve the original name
    wrapper.__name__ = func.__name__

    # Provide a custom __repr__
    def _repr(self=wrapper):
        return f"<function {func.__name__} (updated with {list(updates.keys())})>"
    wrapper.__repr__ = _repr  # type: ignore[attr-defined]

    return wrapper
