import argparse
import json
import os
import subprocess
import sys
from typing import Tuple, Optional

def load_credentials(file_path: str) -> dict:
    if not os.path.isfile(file_path):
        return {}
    with open(file_path, "r", encoding="utf-8") as f:
        try:
            return json.load(f)
        except json.JSONDecodeError:
            return {}

def get_credentials_from_store(ip: str, store_path: str) -> Tuple[Optional[str], Optional[str]]:
    creds = load_credentials(store_path)
    entry = creds.get(ip, {})
    return entry.get("username"), entry.get("password")

def build_ipmitool_cmd(ip: str, user: str, pwd: str, state: str) -> list:
    return [
        "ipmitool",
        "-I", "lanplus",
        "-H", ip,
        "-U", user,
        "-P", pwd,
        "chassis", "power", state
    ]

def main() -> None:
    parser = argparse.ArgumentParser(
        description="Control remote power state via ipmitool."
    )
    parser.add_argument("-i", "--ip", required=True, help="IP address of the remote device")
    parser.add_argument("-u", "--username", help="IPMI username")
    parser.add_argument("-p", "--password", help="IPMI password")
    parser.add_argument(
        "-s", "--state", required=True, choices=["on", "off", "reset", "cycle", "status"],
        help="Desired power state"
    )
    parser.add_argument(
        "-c", "--cred-store", default="credentials.json",
        help="Path to JSON file containing stored credentials (format: {\"IP\": {\"username\": \"...\", \"password\": \"...\"}})"
    )
    parser.add_argument(
        "--dry-run", action="store_true",
        help="Only print the command without executing it"
    )
    args = parser.parse_args()

    ip = args.ip
    user = args.username
    pwd = args.password

    # If username/password not supplied, try to fetch from credential store
    if not user or not pwd:
        stored_user, stored_pwd = get_credentials_from_store(ip, args.cred_store)
        user = user or stored_user
        pwd = pwd or stored_pwd

    if not user or not pwd:
        sys.stderr.write("Error: Missing credentials for IP {}.\n".format(ip))
        sys.exit(1)

    cmd = build_ipmitool_cmd(ip, user, pwd, args.state)
    print("Executing command:", " ".join(cmd))

    if args.dry_run:
        sys.exit(0)

    try:
        result = subprocess.run(
            cmd, capture_output=True, text=True, check=False
        )
        if result.stdout:
            print("Output:\n", result.stdout.strip())
        if result.stderr:
            print("Error:\n", result.stderr.strip(), file=sys.stderr)
        if result.returncode != 0:
            sys.exit(result.returncode)
    except FileNotFoundError:
        sys.stderr.write("Error: ipmitool not found on this system.\n")
        sys.exit(1)
    except Exception as e:
        sys.stderr.write(f"Unexpected error: {e}\n")
        sys.exit(1)

if __name__ == "__main__":
