import os
import json
from typing import Iterator, Optional, Union, Dict, Any

class InputReader:
    """
    Reads data from a local file or an S3 bucket and provides an iterator over its contents.
    """

    def __init__(
        self,
        *,
        source_type: str,
        path: Optional[str] = None,
        bucket: Optional[str] = None,
        key: Optional[str] = None,
        fail_on_missing: bool = True,
    ) -> None:
        """
        Parameters
        ----------
        source_type: str
            Either "file" or "s3".
        path: str, optional
            Path to the local file (required if source_type == "file").
        bucket: str, optional
            Name of the S3 bucket (required if source_type == "s3").
        key: str, optional
            Object key inside the S3 bucket (required if source_type == "s3").
        fail_on_missing: bool
            If True, raise an exception when the file/object does not exist.
        """
        if source_type not in {"file", "s3"}:
            raise ValueError("source_type must be either 'file' or 's3'")

        self.source_type = source_type
        self.path = path
        self.bucket = bucket
        self.key = key
        self.fail_on_missing = fail_on_missing

        # Validate required parameters
        if self.source_type == "file" and not self.path:
            raise ValueError("`path` must be provided for source_type='file'")
        if self.source_type == "s3" and (not self.bucket or not self.key):
            raise ValueError("`bucket` and `key` must be provided for source_type='s3'")

    # --------------------------------------------------------------------- #
    # JSON (de)serialization
    # --------------------------------------------------------------------- #
    @classmethod
    def from_json(cls, data: Union[str, Dict[str, Any]]) -> "InputReader":
        """
        Create an InputReader instance from a JSON string or dict.

        Expected JSON format:
        {
            "source_type": "file" | "s3",
            "path": "...",          # optional, for files
            "bucket": "...",        # optional, for s3
            "key": "...",           # optional, for s3
            "fail_on_missing": true|false
        }
        """
        if isinstance(data, str):
            payload = json.loads(data)
        else:
            payload = data

        return cls(
            source_type=payload["source_type"],
            path=payload.get("path"),
            bucket=payload.get("bucket"),
            key=payload.get("key"),
            fail_on_missing=payload.get("fail_on_missing", True),
        )

    def to_json(self) -> Dict[str, Any]:
        """Return a JSON‑serialisable dict representing this instance."""
        return {
            "source_type": self.source_type,
            "path": self.path,
            "bucket": self.bucket,
            "key": self.key,
            "fail_on_missing": self.fail_on_missing,
        }

    # --------------------------------------------------------------------- #
    # Iterator implementation
    # --------------------------------------------------------------------- #
    def __iter__(self) -> Iterator[str]:
        """Yield lines (as strings) from the configured source."""
        if self.source_type == "file":
            return self._file_iterator()
        else:  # s3
            return self._s3_iterator()

    # --------------------------------------------------------------------- #
    # Private helpers
    # --------------------------------------------------------------------- #
    def _file_iterator(self) -> Iterator[str]:
        if not os.path.exists(self.path):
            if self.fail_on_missing:
                raise FileNotFoundError(f"File not found: {self.path}")
            return iter([])  # empty iterator

        def generator():
            with open(self.path, "r", encoding="utf-8") as f:
                for line in f:
                    yield line.rstrip("\n")

        return generator()

    def _s3_iterator(self) -> Iterator[str]:
        try:
            import boto3
            from botocore.exceptions import ClientError
        except ImportError as exc:
            raise ImportError("boto3 is required for S3 access") from exc

        s3 = boto3.client("s3")

        # Verify existence if required
        if self.fail_on_missing:
            try:
                s3.head_object(Bucket=self.bucket, Key=self.key)
            except ClientError as e:
                raise FileNotFoundError(
                    f"S3 object not found: s3://{self.bucket}/{self.key}"
                ) from e

        def generator():
            try:
                obj = s3.get_object(Bucket=self.bucket, Key=self.key)
                body = obj["Body"]
                for line_bytes in body.iter_lines():
                    yield line_bytes.decode("utf-8")
            except ClientError as e:
                if self.fail_on_missing:
                    raise FileNotFoundError(
                        f"S3 object not found: s3://{self.bucket}/{self.key}"
                    ) from e
                # else: silently end iteration
                return

        return generator()
