import sqlite3

def get_table_schema(db_path: str, table_name: str):
    conn = sqlite3.connect(db_path)
    cur = conn.cursor()

    # Get column info
    cur.execute(f"PRAGMA table_info('{table_name}')")
    columns = [
        {
            "cid": row[0],
            "name": row[1],
            "type": row[2],
            "notnull": bool(row[3]),
            "dflt_value": row[4],
            "pk": bool(row[5]),
        }
        for row in cur.fetchall()
    ]

    # Get index list for the table
    cur.execute(f"PRAGMA index_list('{table_name}')")
    index_list = cur.fetchall()

    indexes = {}
    for idx in index_list:
        # idx schema: (seq, name, unique, origin, partial)
        idx_name = idx[1]
        cur.execute(f"PRAGMA index_info('{idx_name}')")
        idx_info = [
            {
                "seqno": col[0],
                "cid": col[1],
                "name": col[2],
            }
            for col in cur.fetchall()
        ]
        indexes[idx_name] = {
            "unique": bool(idx[2]),
            "origin": idx[3],
            "partial": bool(idx[4]),
            "columns": idx_info,
        }

    conn.close()
    return {"columns": columns, "indexes": indexes}


