using Microsoft.CodeAnalysis.CSharp;

class DynamicExecutor
{
    static void Main(string[] args)
    {
        if (args.Length < 2)
        {
            Console.WriteLine("Usage: DynamicExecutor <source.cs> <arg1> [arg2] ...");
            return;
        }

        string sourcePath = args[0];
        string[] execArgs = args.Skip(1).ToArray();

        if (!File.Exists(sourcePath))
        {
            Console.WriteLine($"Source file not found: {sourcePath}");
            return;
        }

        string sourceCode = File.ReadAllText(sourcePath);
        string exePath = Path.Combine(Path.GetTempPath(), $"Dynamic_{Guid.NewGuid()}.exe");

        var syntaxTree = CSharpSyntaxTree.ParseText(sourceCode);
        var references = AppDomain.CurrentDomain.GetAssemblies()
            .Where(a => !a.IsDynamic && !string.IsNullOrWhiteSpace(a.Location))
            .Select(a => MetadataReference.CreateFromFile(a.Location))
            .Cast<MetadataReference>()
            .ToList();

        var compilation = CSharpCompilation.Create(
            Path.GetFileNameWithoutExtension(exePath),
            new[] { syntaxTree },
            references,
            new CSharpCompilationOptions(OutputKind.ConsoleApplication));

        var result = compilation.Emit(exePath);

        if (!result.Success)
        {
            Console.WriteLine("Compilation failed:");
            foreach (var diagnostic in result.Diagnostics.Where(d => d.Severity == DiagnosticSeverity.Error))
            {
                Console.WriteLine(diagnostic.ToString());
            }
            return;
        }

        var startInfo = new ProcessStartInfo
        {
            FileName = exePath,
            Arguments = string.Join(" ", execArgs.Select(a => $"\"{a}\"")),
            UseShellExecute = false,
            RedirectStandardOutput = true,
            RedirectStandardError = true
        };

        using (var process = Process.Start(startInfo))
        {
            process.OutputDataReceived += (s, e) => { if (e.Data != null) Console.WriteLine(e.Data); };
            process.ErrorDataReceived += (s, e) => { if (e.Data != null) Console.Error.WriteLine(e.Data); };
            process.BeginOutputReadLine();
            process.BeginErrorReadLine();
            process.WaitForExit();
        }

        try { File.Delete(exePath); } catch { }
    }
}

