CREATE OR REPLACE FUNCTION manage_row_triggers(
    p_select_sql   TEXT,               -- SELECT that returns rows with a column "tbl" (table name)
    p_trigger_func REGPROC,           -- function to be called by the trigger
    p_language     NAME DEFAULT 'plpgsql'  -- language to ensure exists
) RETURNS VOID AS
$$
DECLARE
    r               RECORD;
    v_trigger_name  TEXT;
    v_drop_sql      TEXT;
    v_create_sql    TEXT;
    v_exists        BOOLEAN;
BEGIN
    /* -------------------------------------------------
       1. Ensure the required language exists
       ------------------------------------------------- */
    SELECT EXISTS (
        SELECT 1 FROM pg_catalog.pg_language
        WHERE lanname = p_language
    ) INTO v_exists;

    IF NOT v_exists THEN
        EXECUTE format('CREATE LANGUAGE %I', p_language);
    END IF;

    /* -------------------------------------------------
       2. Loop over each row returned by the provided SELECT
          Expecting a column named "tbl" that holds the target table name
       ------------------------------------------------- */
    FOR r IN EXECUTE p_select_sql LOOP
        IF r.tbl IS NULL THEN
            RAISE NOTICE 'Skipping row with NULL table name';
            CONTINUE;
        END IF;

        /* -------------------------------------------------
           Build a deterministic trigger name for this table
           ------------------------------------------------- */
        v_trigger_name := format('auto_trg_%s', r.tbl);

        /* -------------------------------------------------
           3. Drop any existing triggers that match the naming convention
           ------------------------------------------------- */
        FOR v_drop_sql IN
            SELECT tgname
            FROM pg_trigger
            WHERE tgrelid = r.tbl::regclass
              AND tgname LIKE 'auto_trg_%'
        LOOP
            EXECUTE format('DROP TRIGGER %I ON %I', v_drop_sql.tgname, r.tbl);
        END LOOP;

        /* -------------------------------------------------
           4. Create the new trigger on the target table
           ------------------------------------------------- */
        v_create_sql := format(
            'CREATE TRIGGER %I '
            'BEFORE INSERT OR UPDATE ON %I '
            'FOR EACH ROW EXECUTE FUNCTION %s()',
            v_trigger_name,
            r.tbl,
            p_trigger_func
        );

        EXECUTE v_create_sql;
    END LOOP;
END;
$$ LANGUAGE plpgsql;
