    @classmethod
    def filter_by_location_and_audience(cls, location: str, audience: str):
        """
        Return a queryset of events matching the given location and audience.
        """
        return cls.objects.filter(location__iexact=location, audience__iexact=audience)

    def render_page(self, request, password_attempt: str):
        """
        Render the event detail page if the provided password matches.
        """
        if password_attempt != self.password:
            return HttpResponse("Unauthorized", status=401)

        context = {
            "event": self,
        }
        return render(request, "event_detail.html", context)
