public class AntlrRunner {
    public static void main(String[] args) {
        if (args.length < 2) {
            System.err.println("Usage: java AntlrRunner <working-directory> <grammar-file> [options...]");
            System.exit(1);
        }

        File workingDir = new File(args[0]);
        if (!workingDir.isDirectory()) {
            System.err.println("Error: '" + args[0] + "' is not a valid directory.");
            System.exit(1);
        }

        String grammarFile = args[1];

        List<String> command = new ArrayList<>();
        command.add("java");
        command.add("-jar");
        command.add("antlr.jar"); // adjust path/name of the ANTLR jar if needed

        // add any options supplied after the grammar file argument
        for (int i = 2; i < args.length; i++) {
            command.add(args[i]);
        }

        command.add(grammarFile);

        ProcessBuilder pb = new ProcessBuilder(command);
        pb.directory(workingDir);
        pb.redirectErrorStream(false); // keep stdout and stderr separate

        try {
            Process process = pb.start();

            // Capture stdout
            BufferedReader stdOutReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            // Capture stderr
            BufferedReader stdErrReader = new BufferedReader(new InputStreamReader(process.getErrorStream()));

            StringBuilder stdout = new StringBuilder();
            StringBuilder stderr = new StringBuilder();

            Thread outThread = new Thread(() -> {
                String line;
                try {
                    while ((line = stdOutReader.readLine()) != null) {
                        stdout.append(line).append(System.lineSeparator());
                    }
                } catch (IOException e) {
                    // ignore
                }
            });

            Thread errThread = new Thread(() -> {
                String line;
                try {
                    while ((line = stdErrReader.readLine()) != null) {
                        stderr.append(line).append(System.lineSeparator());
                    }
                } catch (IOException e) {
                    // ignore
                }
            });

            outThread.start();
            errThread.start();

            int exitCode = process.waitFor();
            outThread.join();
            errThread.join();

            // Print standard output
            System.out.print(stdout.toString());

            if (exitCode != 0) {
                System.err.println("ANTLR tool exited with error code " + exitCode + ".");
                if (stderr.length() > 0) {
                    System.err.println("Error output:");
                    System.err.print(stderr.toString());
                }
            } else if (stderr.length() > 0) {
                // ANTLR may write warnings to stderr even on success
                System.err.println("Warnings/Errors from ANTLR:");
                System.err.print(stderr.toString());
            }

        } catch (IOException | InterruptedException e) {
            System.err.println("Failed to execute ANTLR tool: " + e.getMessage());
            e.printStackTrace();
            System.exit(1);
        }
    }
}

